// std::endl<char, std::char_traits<char>>(std::basic_ostream<char>&)
//
// Writes '\n' to the stream and flushes it. The compiler inlined the
// virtual-table walk used to reach the underlying locale's ctype facet
// in order to widen '\n' for non-char streams; for the char specialisation
// the widened character is just '\n' itself, so the slow path through
// ctype::do_widen is only taken when the facet is not the default one.
std::ostream &endl(std::ostream &os)
{
    // Reach the stream's ios_base subobject via the vtable's offset-to-top.
    void *ios = (char *)&os + ((const ptrdiff_t *)*(void **)&os)[-3];

    // ios_base::_M_ctype (the cached ctype<char> facet pointer).
    const std::ctype<char> *ctype_facet =
        *(const std::ctype<char> **)((char *)ios + 0xf0);

    if (ctype_facet == nullptr) {
        std::__throw_bad_cast();   // sub_12b0
    }

    char nl;
    if (*((const unsigned char *)ctype_facet + 0x38) != 0) {
        // Fast path: facet has a precomputed widen table — '\n' widens to itself.
        nl = '\n';
    } else {
        // Slow path: force the table to be built, then either use the
        // default widening or call ctype::do_widen('\n').
        ctype_facet->_M_widen_init();                       // sub_1290
        if ((*(char (**)(const std::ctype<char> *, char))
                 ((char *)*(void **)ctype_facet + 0x30))
            == &std::ctype<char>::do_widen) {
            nl = '\n';
        } else {
            nl = ctype_facet->do_widen('\n');
        }
    }

    os.put(nl);            // sub_11b0
    return os.flush();
}

